import * as t from "io-ts";
import { intentTypes } from "./intentType";
import { BaseIntent } from "./baseIntent";
import { TokenEnablement } from "./tokenEnablement";

export const EnableTokenIntent = t.intersection([
  BaseIntent,
  t.type({
    intentType: intentTypes.enableToken,
    enableTokens: t.array(TokenEnablement),
  }),
]);

export type EnableTokenIntent = t.TypeOf<typeof EnableTokenIntent>;
